// Layer 5 — sentinel placeholder is emitted as a normal info line and
// doesn't trigger redaction itself.
func TestSentinelPlaceholder_PassThroughClean(t *testing.T) {
	placeholder := SentinelPlaceholder("openbao-init.sh", "5 shares, root token")
	out := RedactStreamLine(placeholder)
	if out != placeholder {
		t.Errorf("placeholder got mutated: input=%q output=%q", placeholder, out)
	}
	if strings.Contains(placeholder, "abc") || strings.Contains(placeholder, "[REDACTED]") {
		// not testing exact form — just that placeholder is descriptive and not a literal payload
	}
}

// Defense-in-depth: if a sentinel payload DID leak into Info, layer 4
// would still mask it. The runner calls log.Info(SentinelPlaceholder(…))
// for the success path; the test below simulates the failure path
// where a future bug accidentally calls Info with the raw payload.
func TestRedactStreamLine_DefenseInDepth_OpenBaoPayload(t *testing.T) {
	in := `{"unseal_keys_b64":["a1","b2","c3","d4","e5"],"root_token":"s.rootABCDEF"}`
	out := RedactStreamLine(in)
	if strings.Contains(out, "s.rootABCDEF") {
		t.Errorf("payload leaked: %q", out)
	}
}

