func TestTeeChannel_EmitsLines(t *testing.T) {
	lg, _, _ := newTestLogger(t, Options{})
	tee := lg.Tee()

	done := make(chan string, 4)
	go func() {
		for line := range tee {
			done <- line
		}
	}()

	lg.Info("tee-test", "answer", 42)
	// give the tee writer a moment to flush
	time.Sleep(20 * time.Millisecond)

	select {
	case ln := <-done:
		if !strings.Contains(ln, "tee-test") {
			t.Errorf("tee got %q, want substring 'tee-test'", ln)
		}
	case <-time.After(500 * time.Millisecond):
		t.Fatal("tee channel emitted nothing within deadline")
	}
}

func TestTeeChannel_DropOldestWhenFull(t *testing.T) {
	// Build a logger but DON'T drain the tee. After writing more than
	// teeBufferLines records, Write must still succeed (non-blocking).
	lg, _, _ := newTestLogger(t, Options{})
	for i := 0; i < teeBufferLines*2; i++ {
		lg.Info("drop-test", "i", i)
	}
	// If teeWriter blocked, the loop would hang and t fails on timeout.
}

